import type { Currency, TransactionStatus } from '@/types';

export function formatCurrency(amount: number, currency: Currency): string {
  const symbol = currency === 'NGN' ? '₦' : '₵';
  const formatted = new Intl.NumberFormat('en-NG', {
    minimumFractionDigits: currency === 'GHS' ? 2 : 0,
    maximumFractionDigits: currency === 'GHS' ? 2 : 0,
  }).format(amount);
  return `${symbol}${formatted}`;
}

export function formatRelativeTime(isoString: string): string {
  const date = new Date(isoString);
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / 60_000);
  const diffHours = Math.floor(diffMs / 3_600_000);
  const diffDays = Math.floor(diffMs / 86_400_000);
  if (diffMins < 1) return 'Just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays === 1) return 'Yesterday';
  if (diffDays < 7) return `${diffDays}d ago`;
  return date.toLocaleDateString('en-NG', { day: 'numeric', month: 'short' });
}

export interface StatusMeta {
  label: string;
  color: string;
  bg: string;
  dot: string;
}

const STATUS_MAP: Record<TransactionStatus, StatusMeta> = {
  INITIATED:      { label: 'Initiated',    color: 'text-sky-400',    bg: 'bg-sky-400/10',    dot: 'bg-sky-400' },
  NAIRA_DEBITED:  { label: 'Naira debited',color: 'text-violet-400', bg: 'bg-violet-400/10', dot: 'bg-violet-400' },
  USDC_SENT:      { label: 'Bridging',     color: 'text-amber-400',  bg: 'bg-amber-400/10',  dot: 'bg-amber-400' },
  CEDIS_CREDITED: { label: 'Crediting',    color: 'text-blue-400',   bg: 'bg-blue-400/10',   dot: 'bg-blue-400' },
  COMPLETED:      { label: 'Completed',    color: 'text-emerald-400',bg: 'bg-emerald-400/10',dot: 'bg-emerald-400' },
  FAILED:         { label: 'Failed',       color: 'text-red-400',    bg: 'bg-red-400/10',    dot: 'bg-red-400' },
};

export function getStatusMeta(status: TransactionStatus): StatusMeta {
  return STATUS_MAP[status];
}

export function getInitials(name: string): string {
  return name.split(' ').slice(0, 2).map((n) => n[0]).join('').toUpperCase();
}

export function formatFullDate(isoString: string): string {
  return new Date(isoString).toLocaleDateString('en-NG', {
    day: 'numeric',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}
