import type { Transaction, TransactionStatus } from '@/types';
import { formatCurrency } from '@/lib/formatters';

const PIPELINE_STEPS: { status: TransactionStatus; label: string; description: string }[] = [
  { status: 'INITIATED',      label: 'Initiated',     description: 'Payment request received' },
  { status: 'NAIRA_DEBITED',  label: 'Naira debited', description: 'NGN removed from wallet' },
  { status: 'USDC_SENT',      label: 'USDC bridging', description: 'On-chain via Base L2' },
  { status: 'CEDIS_CREDITED', label: 'Crediting GHS', description: 'Recipient bank transfer' },
  { status: 'COMPLETED',      label: 'Completed',     description: 'Funds delivered' },
];

const STATUS_ORDER: TransactionStatus[] = ['INITIATED','NAIRA_DEBITED','USDC_SENT','CEDIS_CREDITED','COMPLETED'];

function getStepState(stepStatus: TransactionStatus, currentStatus: TransactionStatus): 'done' | 'active' | 'pending' {
  if (currentStatus === 'FAILED') return 'pending';
  const stepIdx = STATUS_ORDER.indexOf(stepStatus);
  const currentIdx = STATUS_ORDER.indexOf(currentStatus);
  if (stepIdx < currentIdx) return 'done';
  if (stepIdx === currentIdx) return 'active';
  return 'pending';
}

export function TransferPipelineTracker({ transaction }: { transaction: Transaction }) {
  const { recipientName, senderAmount, senderCurrency, status } = transaction;
  return (
    <section className="rounded-2xl border border-[#1e1e32] bg-[#0f0f1a] p-5">
      <div className="mb-4">
        <h2 className="text-sm font-semibold text-zinc-200">Transfer in progress</h2>
        <p className="mt-0.5 text-[11px] text-zinc-600">To {recipientName} · {formatCurrency(senderAmount, senderCurrency)}</p>
      </div>
      <ol className="flex flex-col gap-0">
        {PIPELINE_STEPS.map((step, i) => {
          const state = getStepState(step.status, status);
          const isLast = i === PIPELINE_STEPS.length - 1;
          return (
            <li key={step.status} className="flex gap-3 relative">
              {!isLast && <div className={`absolute left-[11px] top-7 w-px h-[calc(100%-8px)] ${state === 'done' ? 'bg-indigo-500/40' : 'bg-[#1e1e32]'}`} />}
              <div className="relative z-10 flex-shrink-0 flex items-start pt-[13px]">
                {state === 'done' && (
                  <div className="flex h-[22px] w-[22px] items-center justify-center rounded-full bg-indigo-600">
                    <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                  </div>
                )}
                {state === 'active' && (
                  <div className="flex h-[22px] w-[22px] items-center justify-center rounded-full border-2 border-indigo-400 bg-indigo-400/10">
                    <div className="h-2 w-2 rounded-full bg-indigo-400 animate-pulse" />
                  </div>
                )}
                {state === 'pending' && (
                  <div className="flex h-[22px] w-[22px] items-center justify-center rounded-full border border-[#2a2a45] bg-[#0c0c18]">
                    <span className="text-[9px] font-mono text-zinc-700">{i + 1}</span>
                  </div>
                )}
              </div>
              <div className="pb-4 pt-2.5 flex-1 min-w-0">
                <p className={`text-[12.5px] font-medium leading-none ${state === 'pending' ? 'text-zinc-600' : 'text-zinc-300'}`}>{step.label}</p>
                <p className="mt-1 text-[11px] text-zinc-700">{step.description}</p>
              </div>
            </li>
          );
        })}
      </ol>
    </section>
  );
}
